import{_ as a,o as n,c as i,ag as l}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Profiel","description":"","frontmatter":{},"headers":[],"relativePath":"nl/account/profile.md","filePath":"nl/account/profile.md"}'),t={name:"nl/account/profile.md"};function o(r,e,s,g,d,p){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="profiel" tabindex="-1">Profiel <a class="header-anchor" href="#profiel" aria-label="Permalink to &quot;Profiel&quot;">​</a></h1><p>Beheer je persoonlijke accountinstellingen, voorkeuren en meldingen.</p><h2 id="persoonlijke-informatie" tabindex="-1">Persoonlijke informatie <a class="header-anchor" href="#persoonlijke-informatie" aria-label="Permalink to &quot;Persoonlijke informatie&quot;">​</a></h2><p>Werk je profiel bij via de <strong>Profiel</strong>-pagina:</p><ul><li><strong>Naam</strong> — Je weergavenaam</li><li><strong>E-mail</strong> — Je inlog-e-mail</li><li><strong>Profielfoto</strong> — Upload een foto of avatar</li><li><strong>Taal</strong> — Interfacetaal (Engels, Nederlands, Duits, Frans)</li></ul><h3 id="taal-wijzigen" tabindex="-1">Taal wijzigen <a class="header-anchor" href="#taal-wijzigen" aria-label="Permalink to &quot;Taal wijzigen&quot;">​</a></h3><ol><li>Ga naar <strong>Profiel</strong></li><li>Selecteer je gewenste taal</li><li>De interface wordt direct bijgewerkt</li></ol><p>Je taalinstelling beinvloedt:</p><ul><li>Alle UI-tekst en navigatie</li><li>Datum- en getalnotatie</li><li>Standaardtaal voor nieuwe documenten</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>De factuurtaal wordt per factuur ingesteld en kan afwijken van je interfacetaal. Je kunt een Nederlandse factuur versturen terwijl je de Engelse interface gebruikt.</p></div><h2 id="wachtwoord" tabindex="-1">Wachtwoord <a class="header-anchor" href="#wachtwoord" aria-label="Permalink to &quot;Wachtwoord&quot;">​</a></h2><p>Wijzig je wachtwoord:</p><ol><li>Ga naar <strong>Profiel &gt; Wachtwoord</strong></li><li>Vul je huidige wachtwoord in</li><li>Vul je nieuwe wachtwoord in en bevestig het</li><li>Klik op <strong>Opslaan</strong></li></ol><p>Als je je met Google of Microsoft hebt geregistreerd, kun je alsnog een wachtwoord instellen voor e-mailgebaseerd inloggen.</p><h2 id="meldingsvoorkeuren" tabindex="-1">Meldingsvoorkeuren <a class="header-anchor" href="#meldingsvoorkeuren" aria-label="Permalink to &quot;Meldingsvoorkeuren&quot;">​</a></h2><p>Bepaal welke meldingen je ontvangt en hoe:</p><h3 id="e-mailmeldingen" tabindex="-1">E-mailmeldingen <a class="header-anchor" href="#e-mailmeldingen" aria-label="Permalink to &quot;E-mailmeldingen&quot;">​</a></h3><ul><li><strong>Factuur betaald</strong> — Wanneer een klant een factuur betaalt</li><li><strong>Offerteaanvraag ontvangen</strong> — Wanneer iemand een offerte aanvraagt via je bedrijfspagina</li><li><strong>Teamactiviteit</strong> — Wanneer teamleden acties uitvoeren</li><li><strong>Uitgave goedgekeurd</strong> — Wanneer een uitgave is goedgekeurd</li></ul><h3 id="e-mailsamenvatting" tabindex="-1">E-mailsamenvatting <a class="header-anchor" href="#e-mailsamenvatting" aria-label="Permalink to &quot;E-mailsamenvatting&quot;">​</a></h3><p>Kies hoe vaak je samenvattings-e-mails ontvangt:</p><ul><li><strong>Dagelijks</strong> — Dagelijkse samenvatting van activiteit</li><li><strong>Wekelijks</strong> — Wekelijks overzicht</li><li><strong>Maandelijks</strong> — Maandelijks overzicht</li><li><strong>Uit</strong> — Geen samenvattings-e-mails</li></ul><h3 id="pushmeldingen" tabindex="-1">Pushmeldingen <a class="header-anchor" href="#pushmeldingen" aria-label="Permalink to &quot;Pushmeldingen&quot;">​</a></h3><p>Schakel browserpushmeldingen in voor realtime waarschuwingen wanneer je de app geopend hebt.</p><h3 id="in-app-meldingen" tabindex="-1">In-app-meldingen <a class="header-anchor" href="#in-app-meldingen" aria-label="Permalink to &quot;In-app-meldingen&quot;">​</a></h3><p>Realtime meldingen binnen de MyCompanyDesk-interface. Deze staan altijd aan en verschijnen bij het meldingsbel-icoon in de header.</p><h2 id="gekoppelde-apps" tabindex="-1">Gekoppelde apps <a class="header-anchor" href="#gekoppelde-apps" aria-label="Permalink to &quot;Gekoppelde apps&quot;">​</a></h2><p>Bekijk en beheer OAuth-verbindingen:</p><ul><li><strong>Google</strong> — Gekoppeld voor inloggen en/of Gmail-verzending</li><li><strong>Microsoft</strong> — Gekoppeld voor inloggen en/of Outlook-verzending</li></ul><p>Trek de toegang in om een app los te koppelen van je account.</p>',29)])])}const u=a(t,[["render",o]]);export{h as __pageData,u as default};
